"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[905],{3985:function(e,t,o){o.d(t,{K4:function(){return r},P5:function(){return n},UL:function(){return a}});let a={community:"#3b82f6","consumer-affairs":"#f59e0b","education-1":"#10b981","education-2":"#10b981","employment-1":"#8b5cf6","employment-2":"#8b5cf6",financial:"#ef4444","social-services":"#ec4899","health-1":"#06b6d4","health-2":"#06b6d4","health-3":"#06b6d4","legal-1":"#64748b","legal-2":"#64748b","immigration-1":"#d97706","immigration-2":"#d97706","housing-1":"#84cc16","housing-2":"#84cc16","insurance-1":"#f43f5e","business-1":"#0ea5e9"},n={community:"Community","consumer-affairs":"Consumer Affairs","education-1":"Education","education-2":"Education","employment-1":"Employment","employment-2":"Employment",financial:"Financial","social-services":"Social Services","health-1":"Health","health-2":"Health","health-3":"Mental Health","legal-1":"Legal","legal-2":"Legal","immigration-1":"Immigration","immigration-2":"Immigration","housing-1":"Housing","housing-2":"Housing","insurance-1":"Insurance","business-1":"Business"},r={foundation:"#3b82f6",expansion:"#10b981",intensive:"#f59e0b",mock:"#ef4444"}},4628:function(e){e.exports=JSON.parse('[{"id":"community","domain":"Community","title":"Animal Protection - Neighbour\'s Dog","scenario":"This dialogue is a phone conversation between a resident and an English-speaking staff member of the animal protection centre. The resident is calling the animal protection centre to discuss the welfare of their neighbour\'s dog.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"2019 Test 41 #2060","segments":[{"number":1,"speaker":"ENGLISH","text":"Hello. This is the animal protection society. I\'m Harry. How can I help you today?","wordCount":15},{"number":2,"speaker":"MANDARIN","text":"您好，我觉得我的邻居在虐待他们的狗。我不知道该怎么办。","translation":"Hello. I think my neighbours are mistreating their dog. I\'m not sure what to do.","wordCount":15},{"number":3,"speaker":"ENGLISH","text":"It\'s good that you have called us. Could you tell me why you think the dog is being mistreated?","wordCount":19},{"number":4,"speaker":"MANDARIN","text":"它一直在叫。我想可能是狗不听话。但是当我从围墙上看邻居的后院时，我发现狗根本没有水喝。","translation":"It barks all the time. I thought it was behaving badly. But I looked over the fence into the back yard, and I saw it didn\'t have any water to drink.","wordCount":31},{"number":5,"speaker":"ENGLISH","text":"I see. That\'s not good. Dogs need to have drinking water available all the time. Have you noticed anything else wrong?","wordCount":21},{"number":6,"speaker":"MANDARIN","text":"是的。那条狗很大，但是很瘦。我还能看到它身上的肋骨。狗毛暗淡无光，并缠在一起。我觉得狗很不健康。","translation":"Yes. The dog is quite big, but it\'s very thin. I can see its ribs. Its coat is dull and matted. I don\'t think it looks healthy.","wordCount":27},{"number":7,"speaker":"ENGLISH","text":"You shouldn\'t be able to see its ribs. It doesn\'t sound like it is in good condition. You might be right.","wordCount":21},{"number":8,"speaker":"MANDARIN","text":"我的邻居从来不去遛狗。我本想去敲他们的门，跟他们说一下，可又担心他们可能会不高兴。","translation":"My neighbours never take it for a walk either. I was going to knock on their door, but I thought they might get angry at me.","wordCount":26},{"number":9,"speaker":"ENGLISH","text":"It\'s best not to approach your neighbours. I will write up a report on what you have told me, and our protection officers will visit them.","wordCount":26},{"number":10,"speaker":"MANDARIN","text":"我不想让他们有什么麻烦，但是我确实担心那条狗。","translation":"I don\'t want them to get into trouble, but I am worried about the dog.","wordCount":15},{"number":11,"speaker":"ENGLISH","text":"Don\'t worry. If they are not mistreating the dog, they won\'t get into trouble. We will help them if they need more information on how to take care of the dog.","wordCount":31},{"number":12,"speaker":"MANDARIN","text":"这听起来很好。我希望动物保护工作人员能够尽快来看看。我很高兴跟您打了电话，万一那狗真的需要帮助。","translation":"That sounds good. I hope the protection officers will visit them soon. I\'m glad I called you, in case the dog does need help.","wordCount":24},{"number":13,"speaker":"ENGLISH","text":"I\'m sure they will come in the next few days. If you notice the situation getting worse in the meantime, call us back.","wordCount":23},{"number":14,"speaker":"MANDARIN","text":"我会的。谢谢您接听我的电话。","translation":"I will. Thank you for listening to me.","wordCount":8}],"totalWords":302},{"id":"consumer-affairs","domain":"Consumer Affairs","title":"Tree Trimming Company Complaint","scenario":"In this dialogue, a customer has paid a tree trimming company to remove six trees from their back yard. Simon, the English-speaking owner of the company, cut down four of the trees. He has not returned to complete the work. The customer calls Simon on the telephone to ask him to remove the last two trees.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"2019 Test 35 #2048","segments":[{"number":1,"speaker":"ENGLISH","text":"Good morning. This is Simon from the tree trimming company. How can I help you?","wordCount":15},{"number":2,"speaker":"MANDARIN","text":"西蒙，您好。三周前，您在我房子的后院砍了四棵大树。","translation":"Hello Simon. Three weeks ago, you cut down four large trees in the back yard of my house.","wordCount":18},{"number":3,"speaker":"ENGLISH","text":"Yes, I remember cutting down those trees. That was a hard job because the trees were so close to the fence.","wordCount":21},{"number":4,"speaker":"MANDARIN","text":"我付给您的钱是砍六棵树的。这个工作没完成，我不满意。","translation":"I paid you to cut down six trees. I\'m unhappy the job isn\'t finished.","wordCount":14},{"number":5,"speaker":"ENGLISH","text":"The job took much longer than I expected. I could only remove four trees.","wordCount":14},{"number":6,"speaker":"MANDARIN","text":"您答应会告诉我您什么时候回来完成这项工作。我一直在等您的电话。","translation":"You agreed to let me know when you could return to finish the work. I\'ve been waiting for your telephone call.","wordCount":21},{"number":7,"speaker":"ENGLISH","text":"I\'m sorry that I didn\'t call you. We\'ve been very busy. Let me look at my diary. I can come to your house in four weeks.","wordCount":26},{"number":8,"speaker":"MANDARIN","text":"我不想等那么久。我希望这项工作能在冬天到来之前完成。","translation":"I would prefer not to wait that long. I had hoped this work would be completed before the start of winter.","wordCount":21},{"number":9,"speaker":"ENGLISH","text":"Yes, I know. But the trees will be hard to remove because they are near the fence. It will take longer to do the work.","wordCount":25},{"number":10,"speaker":"MANDARIN","text":"我知道。但是最近有暴风雨。我担心如果风更大的话，树枝会掉到我的房子上。","translation":"I understand. But we\'ve had some storms recently. I\'m worried that the branches will fall on my house if we have more strong wind.","wordCount":24},{"number":11,"speaker":"ENGLISH","text":"Storms are forecasted next week. If the trees are unsafe, I will remove them before then.","wordCount":16},{"number":12,"speaker":"MANDARIN","text":"我想确保我的房子安全，不受损害。您这个星期什么时候过来都行，周末也可以。","translation":"I want to make sure my house is safe from damage. You can come any time this week or on the weekend.","wordCount":22},{"number":13,"speaker":"ENGLISH","text":"I\'ll come on Saturday from 2 p.m. to 5 p.m. If I don\'t finish the work, I\'ll need to return early next week.","wordCount":25},{"number":14,"speaker":"MANDARIN","text":"会不会从我邻居的后院能更容易够得到树呢？我可以问问看是否您可以到她的院子。","translation":"Would it be easier to reach the trees from my neighbour\'s back yard? I could ask if you could go into her yard.","wordCount":23},{"number":15,"speaker":"ENGLISH","text":"That\'s a good idea! I apologise for the delay. I\'ll see you on Saturday at 2 p.m.","wordCount":18}],"totalWords":303},{"id":"education-1","domain":"Education","title":"School Enrolment for Daughter","scenario":"This dialogue is an interview between a mother and a school Principal, Ms Karen Black. The mother is seeking information on how to process her daughter\'s enrolment at the school.","englishSpeakerGender":"Female","loteSpeakerGender":"Female","testId":"2019","segments":[{"number":1,"speaker":"ENGLISH","text":"Good afternoon. I am Karen Black, the Principal. Thank you for your interest in enrolling your daughter at our school.","wordCount":20},{"number":2,"speaker":"MANDARIN","text":"下午好，布莱克女士！非常感谢你安排这次面试！我们刚到澳洲几个月，我希望我女儿可以尽快开始上学。","translation":"Good afternoon, Ms Black. Thank you very much for this interview. We arrived in Australia a few months ago and I would like my daughter to start school as soon as possible.","wordCount":32},{"number":3,"speaker":"ENGLISH","text":"We can help you with the enrolment. Firstly, does your child have any health or medical conditions, such as allergies, that we need to be aware of?","wordCount":27},{"number":4,"speaker":"MANDARIN","text":"没有，我女儿很健康，她已经接种了按她的年龄该接种的所有疫苗。她很聪明，已经懂一些英文了。","translation":"No. My daughter is healthy and has received all the vaccines for her age. She is very intelligent and already understands some English.","wordCount":23},{"number":5,"speaker":"ENGLISH","text":"That is great! She will need to do a proficiency test in English to assess whether she may need language support.","wordCount":21},{"number":6,"speaker":"MANDARIN","text":"她的写作仍然不太好。测试是什么样的？如果她的英文不好，她是不是不会被学校录取？她还很小。","translation":"She still can\'t write well. What will the test be like? Would she not be accepted if she doesn\'t perform well in English? She is still very young.","wordCount":28},{"number":7,"speaker":"ENGLISH","text":"Don\'t worry. The test is suitable for her age. It will assess her understanding of English and basic literacy skills according to the year she will be enrolled in.","wordCount":29},{"number":8,"speaker":"MANDARIN","text":"我还想知道她注册需要哪些文件。我不想让她再缺课了。我担心她会跟不上。","translation":"I would also like to know what documents are necessary for her enrolment. I don\'t want her to miss any more classes. I\'m worried that she will lag behind her classmates.","wordCount":31},{"number":9,"speaker":"ENGLISH","text":"We need proof of residential address, such as a utility bill, as well as the child\'s birth certificate and immunisation records. We will also need parents\' details, visa status and passport copies.","wordCount":32},{"number":10,"speaker":"MANDARIN","text":"好。我会把这些文件准备好，这周晚些时候拿过来。我很高兴她能在这学期开始上课。","translation":"Ok. I am going to organise those documents and I will bring them later this week. I\'m very happy that she can start classes this semester.","wordCount":26},{"number":11,"speaker":"ENGLISH","text":"Is there anything else that you would like to know? Please feel free to contact us if you think of anything else later.","wordCount":23},{"number":12,"speaker":"MANDARIN","text":"没有了，就这些。非常感谢您，布莱克女士！","translation":"No, that\'s all for now. Thank you very much, Ms Black.","wordCount":11}],"totalWords":303},{"id":"education-2","domain":"Education","title":"College Computer Course Enrolment","scenario":"This dialogue is a conversation between Tony an English-speaking employee of a local college and a student who has been accepted on a Computer course. The student is speaking with Tony regards the start date of the course and how to pay the fees.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"2019 Test 41 #2059","segments":[{"number":1,"speaker":"ENGLISH","text":"Welcome to the college. I\'m Tony. How can I help you this morning?","wordCount":13},{"number":2,"speaker":"MANDARIN","text":"您好，托尼。我刚被贵校的电脑课程录取。我有一些问题想问一下。","translation":"Hello Tony. I have just been accepted into a computer course here at the college. I have some questions about it.","wordCount":21},{"number":3,"speaker":"ENGLISH","text":"Well done on being accepted! I\'m sure you will enjoy completing the course. What would you like to know?","wordCount":19},{"number":4,"speaker":"MANDARIN","text":"我收到一个电子邮件，里边有一个注册表格的链接。但是在表格上有两个不同的开学日期。我不知道哪一个日期是正确的。","translation":"I received an email with a link to the enrollment form. But there are two different start dates on the form. I don\'t know which date is correct.","wordCount":28},{"number":5,"speaker":"ENGLISH","text":"If you tell me the name of the course, I can check the start date for you. You don\'t want to miss the first day!","wordCount":25},{"number":6,"speaker":"MANDARIN","text":"我非常盼望参加这个课程的学习。要是错过了开学日，那真是太糟糕了。这是一个初级电脑和信息技术支持课程。","translation":"It would be awful to miss the first day, especially as I\'m looking forward to it so much. It\'s the basic computer and IT support course.","wordCount":26},{"number":7,"speaker":"ENGLISH","text":"There are two classes in that course, a full time class and a part time class. That\'s why there are different start dates.","wordCount":23},{"number":8,"speaker":"MANDARIN","text":"哦，我现在明白了！我是被全日制课程录取了。谢谢。","translation":"Oh I understand now! I have been accepted into the full time class. Thank you.","wordCount":15},{"number":9,"speaker":"ENGLISH","text":"You\'re very welcome. It\'s confusing when there are two classes on the form. Tell me what else you need to know.","wordCount":21},{"number":10,"speaker":"MANDARIN","text":"我还想了解一些学费的问题。我可以分期付款吗？","translation":"I also wanted to ask about fees. Can I pay the course fees in installments?","wordCount":15},{"number":11,"speaker":"ENGLISH","text":"Yes, you can. Once you have filled in the enrollment form, you can speak to our finance office to set up a payment plan.","wordCount":24},{"number":12,"speaker":"MANDARIN","text":"这太好了。分期付款比一次性付清要容易多了，因为我是在学习期间做兼职工作。","translation":"That\'s great. It will be much easier to pay for the course in installments rather than all at once. I\'m only working part time while I study.","wordCount":27},{"number":13,"speaker":"ENGLISH","text":"When your enrollment is processed, you will have a student account. You can pay fees through the account and your course information will be listed there too.","wordCount":27},{"number":14,"speaker":"MANDARIN","text":"这听起来很容易。我现在就填写注册表。谢谢您的帮助，托尼。我真希望早点上课！","translation":"That sounds very easy. I will fill in the enrollment form now. Thank you for your help Tony. I can\'t wait to start my course!","wordCount":25}],"totalWords":309},{"id":"employment-1","domain":"Employment","title":"Job Search at JobActive","scenario":"This dialogue is an interview between Jack, a job search case manager, and a job seeker. The interview takes place in Jack\'s office at JobActive.","englishSpeakerGender":"Male","loteSpeakerGender":"Male","testId":"2019","segments":[{"number":1,"speaker":"ENGLISH","text":"Hello, I\'m Jack. Thank you for coming in.","wordCount":8},{"number":2,"speaker":"MANDARIN","text":"早上好，杰克！很高兴见到您！上次跟我见面的是穆琳，她是不是今天不在呢？","translation":"Good morning Jack. Nice to meet you. Last time I spoke with Maureen. Isn\'t she in today?","wordCount":17},{"number":3,"speaker":"ENGLISH","text":"She\'s on holidays, but I have already looked at your file and just need to discuss a few things with you.","wordCount":21},{"number":4,"speaker":"MANDARIN","text":"好的，您想讨论些什么？我对没工作这件事越来越担心！每周上两次英语课让我没机会好好找工作。","translation":"OK. What needs to be discussed? I\'m getting more worried about not having a job. English classes twice a week doesn\'t give me a chance to properly look for work.","wordCount":30},{"number":5,"speaker":"ENGLISH","text":"I understand. However, you need to look for 10 jobs a month to continue receiving Centrelink payments. Our network connects job seekers with employers, and we\'ll try to help you.","wordCount":30},{"number":6,"speaker":"MANDARIN","text":"我已经在网上开始找工作了，但要做回我的本行，我需要提高英语口语。","translation":"I\'ve already started looking for jobs online. But to continue in my profession, I need to speak better English.","wordCount":19},{"number":7,"speaker":"ENGLISH","text":"What work did you do before coming to Australia?","wordCount":9},{"number":8,"speaker":"MANDARIN","text":"我以前是计算机技术人员，负责系统管理和编程。","translation":"I worked as a computer technician and was responsible for systems administration and programming.","wordCount":14},{"number":9,"speaker":"ENGLISH","text":"You should try other areas until you\'re stronger in English. Your previous experience may be useful. Some companies offer training in areas where you may not need 100% English fluency.","wordCount":32},{"number":10,"speaker":"MANDARIN","text":"如果您可以安排让我去 IT 公司面试就太好了！这样我就有机会继续留在计算机这一行业。","translation":"It would be fantastic if you could arrange interviews for me with IT organisations. I\'d have the opportunity to continue in the field of computing.","wordCount":25},{"number":11,"speaker":"ENGLISH","text":"We\'ll see. You must prepare a r\xe9sum\xe9. We can help you write one.","wordCount":13},{"number":12,"speaker":"MANDARIN","text":"谢谢。您能帮助我使用寻工服务和网上招工列表吗？","translation":"Thank you. Can you also help me use the Job Services and the online job listing?","wordCount":16},{"number":13,"speaker":"ENGLISH","text":"Definitely. You can also use the job search tools in the Centrelink computers. We\'ll schedule another interview for next week and finalise the finer points.","wordCount":25},{"number":14,"speaker":"MANDARIN","text":"我感到更有希望、更乐观了！我要去买一件初次面试时穿的新衬衫。我要赶快走了，上课要迟到了。再见！","translation":"I\'m more hopeful and more optimistic! I\'ll even buy a new shirt for the first interview. I need to run now not to be late for my class. Bye!","wordCount":29},{"number":15,"speaker":"ENGLISH","text":"We\'ll select available jobs and next time we may have good news and you\'ll be able to wear your new shirt. Bye!","wordCount":22}],"totalWords":310},{"id":"employment-2","domain":"Employment","title":"Part-time Campus Job Inquiry","scenario":"This dialogue is a conversation between a university student and Mark, an English-speaking Student advisor at the student centre about jobs. The student would like to get a part time job on campus to help pay for expenses.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"2019 Test 39 #2056","segments":[{"number":1,"speaker":"ENGLISH","text":"Hi, welcome to the university student centre. My name is Mark. How can I help you today?","wordCount":17},{"number":2,"speaker":"MANDARIN","text":"你好，马克。我想询问一下关于学生找工作的事情。我的朋友说在校园内可能有工作。","translation":"Hi Mark. I\'m enquiring about jobs for students. A friend mentioned that there may be work available on campus.","wordCount":19},{"number":3,"speaker":"ENGLISH","text":"The university has an employment website which lists all job vacancies on campus. There are full time and part time jobs available.","wordCount":22},{"number":4,"speaker":"MANDARIN","text":"我在找兼职的工作。我觉得我无法应付全职工作，我的课程非常繁重。","translation":"I am looking for a part time job. I don\'t think I would be able to manage a full time job. My course is very demanding.","wordCount":26},{"number":5,"speaker":"ENGLISH","text":"I understand. I know it\'s very hard for students to work full time and study. That\'s why part time jobs on campus are so popular.","wordCount":25},{"number":6,"speaker":"MANDARIN","text":"兼职工作多吗？我想尽快找到工作来帮补生活开支。我在多个领域有工作经验。","translation":"Are there many part time jobs available? I would like to find work as soon as possible to help with my living expenses. I have experience in several areas.","wordCount":29},{"number":7,"speaker":"ENGLISH","text":"The university is currently taking applications for waiters and kitchen staff to work in the function centre. Have you had any experience working at cafes or restaurants?","wordCount":27},{"number":8,"speaker":"MANDARIN","text":"我在一家咖啡厅当过服务员。我也做过厨房帮工。你能提供更详细的信息吗？或者我应该浏览一下大学的网站？","translation":"I have had some experience as a waiter in a cafe. I have also worked as a kitchenhand. Do you have more information, or should I look on the university website?","wordCount":31},{"number":9,"speaker":"ENGLISH","text":"I can give you some information, but you will need to look at the website for all the details. You also apply for jobs on the website.","wordCount":27},{"number":10,"speaker":"MANDARIN","text":"那太好了。今天晚些时候我会浏览一下网站，顺便申请适合我的工作。","translation":"That\'s great. I will look at the website later today and put in an application for any jobs that are suitable.","wordCount":21},{"number":11,"speaker":"ENGLISH","text":"Good luck. If you miss out on getting a job at the function centre this time, keep checking the website. New jobs are listed regularly.","wordCount":25},{"number":12,"speaker":"MANDARIN","text":"我会这么做的。希望不久我就能找到新工作。感谢你的帮助！","translation":"I will do that. I\'m hoping it won\'t be long before I have a new job. Thank you for helping me!","wordCount":21}],"totalWords":290},{"id":"financial","domain":"Financial","title":"Home Loan Application at Bank","scenario":"This dialogue takes place between Mr Wilson, a loan manager at a Sydney Bank and a client who has made an appointment to see him. The client wants to purchase a property and is enquiring about how to apply for a loan.","englishSpeakerGender":"Male","loteSpeakerGender":"Female","testId":"2019","segments":[{"number":1,"speaker":"ENGLISH","text":"Hello, my name is Justin Wilson. I understand you are booked in with me today to discuss a loan, is that right?","wordCount":22},{"number":2,"speaker":"MANDARIN","text":"没错!我终于找到了一间价格合理的公寓，我想买下来，所以我有几个问题。","translation":"Yes, that\'s right. I finally found an apartment for a decent price and I\'m thinking of buying it, so I have a few questions.","wordCount":24},{"number":3,"speaker":"ENGLISH","text":"You\'ve come to the right place. How can I help?","wordCount":10},{"number":4,"speaker":"MANDARIN","text":"我想知道如何获得贷款，利率是多少，需要多少首付。","translation":"I would like to know how to obtain financing, what is the interest rate and how much deposit is needed.","wordCount":20},{"number":5,"speaker":"ENGLISH","text":"I can certainly assist you with all that. How about we start by talking about the property you are interested in?","wordCount":21},{"number":6,"speaker":"MANDARIN","text":"好啊。","translation":"Yes, perfect.","wordCount":2},{"number":7,"speaker":"ENGLISH","text":"What caught your eye in this property? And how much is it valued at?","wordCount":14},{"number":8,"speaker":"MANDARIN","text":"是一套非常小的两卧室公寓。地板是最近翻新的，位置很不错，靠近我需要的一切。","translation":"It is a very small two-bedroom apartment. The floor has been recently renovated and the location is great, near everything I need.","wordCount":23},{"number":9,"speaker":"ENGLISH","text":"Fantastic. Do you have the financial details for the property, such as the price and rates?","wordCount":16},{"number":10,"speaker":"MANDARIN","text":"房地产中介的女士说，业主会考虑接受 60 万以上的出价。这有点超出我的预算，但这套公寓很难得。","translation":"The lady from the real estate agency said the owner is accepting offers above $600,000. It is a little over what I had planned, but it is a great find.","wordCount":33},{"number":11,"speaker":"ENGLISH","text":"Certainly. We need to work out if you have enough savings for the deposit and whether you can borrow the rest.","wordCount":21},{"number":12,"speaker":"MANDARIN","text":"这套房子需要多少首付？","translation":"And how much would the deposit for this property be?","wordCount":10},{"number":13,"speaker":"ENGLISH","text":"You need at least 10% of the total value, plus enough to cover other rates and expenses.","wordCount":18},{"number":14,"speaker":"MANDARIN","text":"好的，跟我想的差不多。我有 7 万块存款可以用来付首付和杂费。那银行会借给我剩下的部分吗？","translation":"Ok, that is what I figured. I already have $70,000 saved to cover the deposit and fees. Will the bank lend me the rest?","wordCount":26},{"number":15,"speaker":"ENGLISH","text":"Let\'s use our loan calculator to work out how much you can borrow. I need to ask you some personal questions in order to assess your income.","wordCount":27},{"number":16,"speaker":"MANDARIN","text":"当然可以！我今天把所有文件都带来了，这样我们马上就可以开始。","translation":"Of course. I gathered all my documents and brought them with me today so that we can get started straight away.","wordCount":21}],"totalWords":308},{"id":"social-services","domain":"Social Services","title":"Centrelink Youth Allowance","scenario":"This dialogue takes place over the phone between a mother and a Centrelink Social Worker, Melinda. Melinda wants to discuss the son\'s application for Youth Allowance. The son has told Melinda that he cannot live with his Mum and is applying for the Living Away from Home Allowance because of conflict in the home.","englishSpeakerGender":"Female","loteSpeakerGender":"Female","testId":"2019","segments":[{"number":1,"speaker":"ENGLISH","text":"Hello, my name is Melinda, I\'m a social worker at Centrelink. Do you have a minute to talk about your son?","wordCount":21},{"number":2,"speaker":"MANDARIN","text":"我正准备去超市，但可以等下再去。我儿子怎么了？","translation":"I was just about to go to the supermarket but it can wait. Has something happened to my son?","wordCount":19},{"number":3,"speaker":"ENGLISH","text":"Everything is fine. Your son has applied for Youth Allowance and I need to speak to you about his circumstances. He said that you had an argument and you told him to leave the house.","wordCount":35},{"number":4,"speaker":"MANDARIN","text":"是的，我们吵了一架。我告诉他，住在我家里时，必须规矩点，不要再跟他的一些朋友见面。我听说他们跟毒品有关。","translation":"Yes, we had an argument and I told him that while he is living under my roof he has to behave and stop seeing some of his friends. I heard they are involved with drugs.","wordCount":35},{"number":5,"speaker":"ENGLISH","text":"Well, your son told me a slightly different story. He said that he wasn\'t allowed to return home, so I was considering granting him Youth Allowance at the Living Away from Home rate.","wordCount":33},{"number":6,"speaker":"MANDARIN","text":"只有他不规矩时才不让他回家！我是单身，还有另外两个孩子要照顾。生活虽然很艰难，但我的门总是对他敞开着。我只是希望他安全。","translation":"Only if he doesn\'t behave! I\'m on my own with another 2 children to look after. Life\'s tough right now but my door is always open for him. I just want him to be safe.","wordCount":35},{"number":7,"speaker":"ENGLISH","text":"It sounds like it\'s been hard for you bringing up 3 children on your own. Would you like to come into the office to discuss a few options on how we could help you?","wordCount":34},{"number":8,"speaker":"MANDARIN","text":"我没时间去你们办公室。我每天工作几个小时，还要去学校接孩子。","translation":"I don\'t have time to go to the office. I work a few hours every day and then I have to pick up my children from school.","wordCount":27},{"number":9,"speaker":"ENGLISH","text":"How about over the phone? I can refer you to some services, like mediation, parent support groups and community organisations.","wordCount":20},{"number":10,"speaker":"MANDARIN","text":"好的，我们可以预约后天，在我去学校接完孩子以后。","translation":"OK, we can make an appointment for the day after tomorrow after I pick up the kids from school.","wordCount":19},{"number":11,"speaker":"ENGLISH","text":"How does 3.30 sound?","wordCount":5},{"number":12,"speaker":"MANDARIN","text":"3:30可以。这样我有时间为孩子们准备点心，他们到家时总是觉得饿。","translation":"3:30 is OK. That gives me time to make a snack for the kids; they are always starving when they get home!","wordCount":23}],"totalWords":306},{"id":"health-1","domain":"Health","title":"GP Visit - Food Poisoning","scenario":"This dialogue is a consultation between a patient and their GP, Dr Smith. The patient has come to the clinic complaining of stomach pain, vomiting, and diarrhoea after eating takeaway food the previous night.","englishSpeakerGender":"Female","loteSpeakerGender":"Either","testId":"Practice Batch 1 #001","segments":[{"number":1,"speaker":"ENGLISH","text":"Good morning. I\'m Dr Smith. Please take a seat. What brings you in today?","wordCount":14},{"number":2,"speaker":"MANDARIN","text":"医生您好。我昨天晚上吃了外卖之后就一直肚子痛，还呕吐了好几次，拉肚子也很严重。","translation":"Hello doctor. I\'ve had stomach pain since eating takeaway last night. I\'ve vomited several times and the diarrhoea has been quite severe.","wordCount":22},{"number":3,"speaker":"ENGLISH","text":"I\'m sorry to hear that. Can you tell me what you ate and roughly what time you had the meal?","wordCount":20},{"number":4,"speaker":"MANDARIN","text":"大概晚上七点左右，我点了一份炒饭和一份糖醋鸡。吃完大概两个小时就开始不舒服了。","translation":"Around seven in the evening, I ordered fried rice and sweet and sour chicken. About two hours after eating, I started feeling unwell.","wordCount":23},{"number":5,"speaker":"ENGLISH","text":"That does sound like it could be food poisoning. Have you been able to keep any fluids down since then?","wordCount":20},{"number":6,"speaker":"MANDARIN","text":"我试着喝了一些水，但是大部分都吐出来了。今天早上稍微好了一点，能喝几口水了。","translation":"I tried drinking some water but most of it came back up. This morning it\'s slightly better and I can manage a few sips.","wordCount":24},{"number":7,"speaker":"ENGLISH","text":"It\'s important to stay hydrated. Do you have any allergies to medications that I should know about before I prescribe anything?","wordCount":21},{"number":8,"speaker":"MANDARIN","text":"我对青霉素过敏，其他的药物应该没有问题。我以前也没有什么大的健康问题。","translation":"I\'m allergic to penicillin, but I should be fine with other medications. I haven\'t had any major health issues before.","wordCount":20},{"number":9,"speaker":"ENGLISH","text":"Thank you for letting me know. I\'ll note that down. Have you noticed any blood in your vomit or stools? And do you have a fever?","wordCount":26},{"number":10,"speaker":"MANDARIN","text":"没有看到血，但是我昨晚量了一下体温，有三十八度二。今天早上好像退了一些。","translation":"I haven\'t noticed any blood, but I checked my temperature last night and it was 38.2 degrees. It seems to have come down a bit this morning.","wordCount":27},{"number":11,"speaker":"ENGLISH","text":"A mild fever is common with food poisoning. I\'ll prescribe an anti-nausea medication and oral rehydration sachets. Stick to bland foods like toast and crackers for a couple of days.","wordCount":30},{"number":12,"speaker":"MANDARIN","text":"好的，谢谢医生。我需要请假在家休息吗？大概多久才能好？","translation":"Thank you, doctor. Should I take time off work to rest at home? How long will it take to recover?","wordCount":20},{"number":13,"speaker":"ENGLISH","text":"I\'d recommend at least two days off work. Most food poisoning clears up within three to five days. If symptoms worsen or you develop a high fever, come back or visit emergency.","wordCount":32},{"number":14,"speaker":"MANDARIN","text":"明白了。如果需要的话，您能帮我开一个病假条吗？我需要交给公司。","translation":"I understand. Could you write me a medical certificate if needed? I need to give one to my employer.","wordCount":19}],"totalWords":318},{"id":"health-2","domain":"Health","title":"Hospital - Child Vaccination","scenario":"This dialogue takes place at a community health centre where a parent has brought their child for routine vaccinations. The nurse explains the vaccines being administered, possible side effects, and the consent process.","englishSpeakerGender":"Female","loteSpeakerGender":"Female","testId":"Practice Batch 1 #002","segments":[{"number":1,"speaker":"ENGLISH","text":"Good morning. I\'m Nurse Jennifer. I understand you\'ve brought your child in for their scheduled vaccinations today. Can you confirm the child\'s name and date of birth?","wordCount":27},{"number":2,"speaker":"MANDARIN","text":"早上好。我女儿叫李美琳，出生日期是二零二二年三月十五号。她今天要打四岁的常规疫苗。","translation":"Good morning. My daughter\'s name is Li Meilin, born on the fifteenth of March 2022. She\'s here for her four-year-old routine vaccinations.","wordCount":22},{"number":3,"speaker":"ENGLISH","text":"Thank you. Today she\'ll be receiving two vaccines. The first is a combined vaccine for diphtheria, tetanus, whooping cough, and polio. The second is for measles, mumps, and rubella.","wordCount":29},{"number":4,"speaker":"MANDARIN","text":"好的。这些疫苗有什么副作用吗？上次打针之后她手臂肿了好几天，我有点担心。","translation":"I see. Are there any side effects from these vaccines? Last time after her injection her arm was swollen for several days and I\'m a bit worried.","wordCount":27},{"number":5,"speaker":"ENGLISH","text":"Some swelling and redness at the injection site is normal and usually goes away within a few days. She may also have a mild fever. You can give her children\'s paracetamol if needed.","wordCount":33},{"number":6,"speaker":"MANDARIN","text":"如果出现比较严重的反应怎么办？比如高烧或者过敏反应？","translation":"What should I do if she has a more serious reaction? For example, a high fever or an allergic reaction?","wordCount":20},{"number":7,"speaker":"ENGLISH","text":"Serious reactions are very rare. However, if she develops a high fever, a rash all over her body, or has difficulty breathing, take her to the nearest emergency department immediately.","wordCount":30},{"number":8,"speaker":"MANDARIN","text":"明白了。打完针之后我们需要在这里等一会儿吗？","translation":"I understand. Do we need to wait here for a while after the injection?","wordCount":14},{"number":9,"speaker":"ENGLISH","text":"Yes, we ask that you stay in the waiting area for fifteen minutes after the vaccination so we can monitor for any immediate reactions. Before we proceed, I need you to sign a consent form.","wordCount":35},{"number":10,"speaker":"MANDARIN","text":"没问题。请问这些疫苗是免费的吗？还是我们需要付费？","translation":"No problem. Are these vaccines free of charge or do we need to pay?","wordCount":14},{"number":11,"speaker":"ENGLISH","text":"All childhood vaccinations on the National Immunisation Program schedule are free. The record will be updated on the Australian Immunisation Register, and you can access it through your myGov account.","wordCount":30},{"number":12,"speaker":"MANDARIN","text":"太好了。那我现在就签同意书吧。打完针之后回家有什么需要注意的吗？","translation":"That\'s great. I\'ll sign the consent form now then. Is there anything I should look out for when we get home after the injection?","wordCount":24}],"totalWords":305},{"id":"health-3","domain":"Health","title":"Mental Health Counselling - Work Stress and Anxiety","scenario":"This dialogue is a session between a worker and a mental health counsellor. The worker is experiencing anxiety, trouble sleeping, and stress from work overload. The counsellor discusses coping strategies and possible referral options.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"Practice Batch 1 #003","segments":[{"number":1,"speaker":"ENGLISH","text":"Good afternoon. I\'m David, a counsellor here at the community health centre. How are you feeling today?","wordCount":17},{"number":2,"speaker":"MANDARIN","text":"你好。说实话，我最近压力很大。工作上的事情让我喘不过气来，晚上也睡不好觉。","translation":"Hello. To be honest, I\'ve been under a lot of stress lately. Work has been overwhelming and I can\'t sleep well at night.","wordCount":23},{"number":3,"speaker":"ENGLISH","text":"I appreciate you sharing that with me. Can you tell me a bit more about what\'s been happening at work?","wordCount":20},{"number":4,"speaker":"MANDARIN","text":"我在一家会计事务所工作，最近公司裁员了，走了好几个同事，他们的工作全部压到了我身上。我每天都加班到很晚。","translation":"I work at an accounting firm. Recently the company had layoffs and several colleagues left. All their work has been piled onto me. I work overtime every day until very late.","wordCount":31},{"number":5,"speaker":"ENGLISH","text":"That sounds like a very stressful situation. How long has this been going on, and have you noticed any other symptoms besides trouble sleeping?","wordCount":24},{"number":6,"speaker":"MANDARIN","text":"大概有两三个月了。我经常感到心跳加速，有时候手会发抖。早上起来的时候特别焦虑，不想去上班。","translation":"It\'s been about two to three months. I often feel my heart racing and sometimes my hands shake. I feel especially anxious in the morning and don\'t want to go to work.","wordCount":32},{"number":7,"speaker":"ENGLISH","text":"Those are common symptoms of anxiety. Have you spoken to your GP about how you\'ve been feeling? It might be helpful to get a medical assessment as well.","wordCount":28},{"number":8,"speaker":"MANDARIN","text":"还没有。我一直觉得自己应该能撑过去。在我们的文化里，看心理医生好像有点不好意思。","translation":"Not yet. I\'ve always thought I should be able to push through it. In our culture, seeing a mental health professional can feel a bit embarrassing.","wordCount":26},{"number":9,"speaker":"ENGLISH","text":"There\'s absolutely no shame in seeking help. I\'d recommend seeing your GP and asking about a Mental Health Treatment Plan under Medicare. This gives you up to ten subsidised sessions with a psychologist each year.","wordCount":35},{"number":10,"speaker":"MANDARIN","text":"这个我没听说过。看心理医生的费用会全部由Medicare报销吗？","translation":"I haven\'t heard of that before. Will the cost of seeing a psychologist be fully covered by Medicare?","wordCount":18},{"number":11,"speaker":"ENGLISH","text":"Medicare will cover part of the cost. Some psychologists bulk bill, which means there\'s no out-of-pocket cost for you. I can give you a list of bulk-billing psychologists in the area.","wordCount":31},{"number":12,"speaker":"MANDARIN","text":"那太好了。在等待预约的这段时间，有什么我自己可以做的来缓解焦虑吗？","translation":"That would be great. While I\'m waiting for an appointment, is there anything I can do on my own to manage the anxiety?","wordCount":23},{"number":13,"speaker":"ENGLISH","text":"Yes, there are several things. Try deep breathing exercises, limit caffeine, and set a regular sleep routine. Even a short daily walk can help. I\'ll give you a brochure on relaxation techniques.","wordCount":32},{"number":14,"speaker":"MANDARIN","text":"谢谢你，这些建议都很实用。我会先去找我的家庭医生，然后按照你说的方法试试看。","translation":"Thank you, these suggestions are very practical. I\'ll see my GP first and then try the methods you\'ve mentioned.","wordCount":19}],"totalWords":359},{"id":"legal-1","domain":"Legal","title":"Police Report - Burglary","scenario":"This dialogue is between a resident and a police officer at the local police station. The resident is reporting a burglary that occurred at their home while they were at work.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"Practice Batch 1 #004","segments":[{"number":1,"speaker":"ENGLISH","text":"Good afternoon. I\'m Senior Constable Williams. I understand you\'d like to report a break-in. Can you tell me what happened?","wordCount":20},{"number":2,"speaker":"MANDARIN","text":"是的，警官。我今天下午五点左右下班回家，发现后门的玻璃被打碎了，家里被翻得乱七八糟。","translation":"Yes, officer. When I got home from work around five this afternoon, I found the glass on the back door had been smashed and the house was a complete mess.","wordCount":30},{"number":3,"speaker":"ENGLISH","text":"I\'m sorry to hear that. Before we go further, can I confirm you haven\'t touched or moved anything inside? It\'s important to preserve the scene for forensics.","wordCount":27},{"number":4,"speaker":"MANDARIN","text":"我进去之后发现情况不对就马上出来了，没有碰任何东西。我站在门口打的电话报警。","translation":"I went in and realised something was wrong, so I came straight back out without touching anything. I called the police from the doorway.","wordCount":24},{"number":5,"speaker":"ENGLISH","text":"That was the right thing to do. Can you tell me what items appear to be missing or stolen?","wordCount":19},{"number":6,"speaker":"MANDARIN","text":"我的笔记本电脑不见了，还有放在卧室抽屉里的一些现金，大概有五百澳元。我太太的几件首饰好像也被拿走了。","translation":"My laptop is missing, along with some cash that was in the bedroom drawer, about five hundred dollars. Some of my wife\'s jewellery also appears to have been taken.","wordCount":29},{"number":7,"speaker":"ENGLISH","text":"Do you have the serial number for the laptop or any receipts for the jewellery? That information would help us if the items are recovered.","wordCount":25},{"number":8,"speaker":"MANDARIN","text":"笔记本电脑的序列号我应该在保修单上能找到。首饰的话，我太太可能有购买收据，我回去找一下。","translation":"I should be able to find the serial number for the laptop on the warranty card. As for the jewellery, my wife might have the purchase receipts. I\'ll look for them.","wordCount":31},{"number":9,"speaker":"ENGLISH","text":"That would be very helpful. Do you have any security cameras or know of any CCTV in the area that might have captured something?","wordCount":24},{"number":10,"speaker":"MANDARIN","text":"我家没有装监控摄像头。但是我对面邻居的门口好像有一个摄像头，也许能拍到什么。","translation":"I don\'t have any security cameras at my house. But my neighbour across the street seems to have a camera at their front door which might have captured something.","wordCount":29},{"number":11,"speaker":"ENGLISH","text":"We\'ll speak to your neighbour about that. Did any of your neighbours see or hear anything unusual during the day?","wordCount":20},{"number":12,"speaker":"MANDARIN","text":"我还没来得及问。不过隔壁的张太太白天一般都在家，她可能注意到了什么可疑的情况。","translation":"I haven\'t had a chance to ask yet. But Mrs Zhang next door is usually home during the day, so she might have noticed something suspicious.","wordCount":26},{"number":13,"speaker":"ENGLISH","text":"We\'ll follow up with her too. I\'ll send a forensic team to check for fingerprints and evidence. I\'ll also prepare a report and give you an event number for your insurance claim.","wordCount":32},{"number":14,"speaker":"MANDARIN","text":"谢谢警官。我需要这个事件编号来向保险公司报案。请问大概多久能有调查结果？","translation":"Thank you, officer. I need that event number to lodge a claim with my insurance company. How long will the investigation take approximately?","wordCount":23}],"totalWords":359},{"id":"legal-2","domain":"Legal","title":"Legal Aid - Domestic Violence Support","scenario":"This dialogue takes place at a Legal Aid office. A person has contacted Legal Aid seeking help regarding a violent partner. The lawyer explains the Apprehended Violence Order (AVO) process, available support services, and temporary accommodation options.","englishSpeakerGender":"Female","loteSpeakerGender":"Female","testId":"Practice Batch 1 #005","segments":[{"number":1,"speaker":"ENGLISH","text":"Good morning. I\'m Sarah, a solicitor with Legal Aid. Everything you tell me today is confidential. How can I help you?","wordCount":21},{"number":2,"speaker":"MANDARIN","text":"你好。我丈夫最近对我越来越暴力。上周他打了我，我的手臂上还有淤青。我很害怕，不知道该怎么办。","translation":"Hello. My husband has become increasingly violent towards me recently. Last week he hit me and I still have bruises on my arm. I\'m very scared and don\'t know what to do.","wordCount":32},{"number":3,"speaker":"ENGLISH","text":"I\'m very sorry you\'re going through this. You\'ve done the right thing by coming here. Your safety is the priority. Are you currently living with your husband?","wordCount":27},{"number":4,"speaker":"MANDARIN","text":"是的，我们还住在一起。我想离开，但是我没有其他地方可以去。我在澳洲也没有什么家人。","translation":"Yes, we still live together. I want to leave but I have nowhere else to go. I don\'t have any family in Australia either.","wordCount":24},{"number":5,"speaker":"ENGLISH","text":"There are safe options for you. We can help you apply for an Apprehended Violence Order, or AVO. This is a court order that prevents your husband from contacting or approaching you.","wordCount":32},{"number":6,"speaker":"MANDARIN","text":"申请这个保护令需要多长时间？在等待期间他会不会对我更加暴力？我真的很担心自己的安全。","translation":"How long does it take to apply for this protection order? Will he become more violent towards me while I\'m waiting? I\'m really worried about my safety.","wordCount":27},{"number":7,"speaker":"ENGLISH","text":"If you\'re in immediate danger, police can issue a provisional AVO on the spot, which takes effect straight away. We can also arrange emergency accommodation at a women\'s refuge.","wordCount":29},{"number":8,"speaker":"MANDARIN","text":"我有一个五岁的女儿。她也能跟我一起去庇护所吗？我不想把她留在那个环境里。","translation":"I have a five-year-old daughter. Can she come with me to the refuge? I don\'t want to leave her in that environment.","wordCount":22},{"number":9,"speaker":"ENGLISH","text":"Absolutely. Your daughter can stay with you at the refuge. The refuge also provides counselling and support services for both you and your child.","wordCount":24},{"number":10,"speaker":"MANDARIN","text":"我的签证是跟我丈夫绑定的。如果我离开他，会不会影响我的签证身份？","translation":"My visa is tied to my husband. If I leave him, will it affect my visa status?","wordCount":17},{"number":11,"speaker":"ENGLISH","text":"If you\'re on a partner visa, there are special provisions for family violence situations. You may still be eligible to stay in Australia. I can refer you to an immigration lawyer for help.","wordCount":33},{"number":12,"speaker":"MANDARIN","text":"这让我放心多了。除了法律帮助，还有其他什么支持服务可以帮助我吗？","translation":"That\'s a great relief. Apart from legal assistance, are there any other support services that can help me?","wordCount":18},{"number":13,"speaker":"ENGLISH","text":"Yes. I can connect you with a domestic violence support worker who speaks Mandarin. There\'s also a national helpline called 1800RESPECT that operates around the clock. They can help with safety planning and emotional support.","wordCount":35},{"number":14,"speaker":"MANDARIN","text":"谢谢你。我想尽快申请那个保护令，也想了解一下去庇护所的安排。","translation":"Thank you. I\'d like to apply for the protection order as soon as possible and also find out about the arrangements for the refuge.","wordCount":24}],"totalWords":365},{"id":"immigration-1","domain":"Immigration","title":"Citizenship Application - Interview","scenario":"This dialogue takes place at the Department of Home Affairs during a citizenship interview. An officer interviews an applicant about their residency, character requirements, knowledge of Australia, and explains the citizenship ceremony process.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"Practice Batch 1 #006","segments":[{"number":1,"speaker":"ENGLISH","text":"Good morning. I\'m James, a citizenship officer with the Department of Home Affairs. Thank you for attending your citizenship interview today. Can I see your identification, please?","wordCount":27},{"number":2,"speaker":"MANDARIN","text":"早上好。这是我的护照和永居签证的确认信。我已经期待这一天很久了。","translation":"Good morning. Here is my passport and the confirmation letter for my permanent residency visa. I\'ve been looking forward to this day for a long time.","wordCount":26},{"number":3,"speaker":"ENGLISH","text":"Thank you. I can see from your records that you were granted permanent residency in January 2022. Can you confirm how long you have been living in Australia?","wordCount":28},{"number":4,"speaker":"MANDARIN","text":"我是二零二一年七月来到澳洲的，到现在已经住了差不多四年半了。这段时间我只出过两次国，每次大概两个星期。","translation":"I arrived in Australia in July 2021, so I\'ve been living here for about four and a half years. During this time, I\'ve only been overseas twice, for about two weeks each time.","wordCount":33},{"number":5,"speaker":"ENGLISH","text":"That\'s fine. The residency requirement is that you\'ve lived in Australia for at least four years, with at least one year as a permanent resident. You appear to meet that requirement.","wordCount":31},{"number":6,"speaker":"MANDARIN","text":"太好了。我一直在悉尼生活和工作，也在这里交了很多朋友。我的两个孩子都在本地的学校上学。","translation":"That\'s great. I\'ve been living and working in Sydney and have made many friends here. Both of my children attend local schools.","wordCount":22},{"number":7,"speaker":"ENGLISH","text":"That\'s wonderful. Now I need to ask about the character requirement. Have you had any criminal convictions or any issues with the law in Australia or overseas?","wordCount":27},{"number":8,"speaker":"MANDARIN","text":"没有，我从来没有违反过法律。我有一份稳定的工作，一直按时纳税，也没有任何犯罪记录。","translation":"No, I have never broken the law. I have a stable job, I\'ve always paid my taxes on time, and I have no criminal record.","wordCount":25},{"number":9,"speaker":"ENGLISH","text":"Very good. I can see you\'ve already passed the citizenship test, which covers knowledge of Australia, including its democratic values, history, and national symbols. Congratulations on that.","wordCount":27},{"number":10,"speaker":"MANDARIN","text":"谢谢。我为那个考试准备了很长时间，学到了很多关于澳洲历史和政府体系的知识。请问接下来的流程是什么？","translation":"Thank you. I prepared for that test for a long time and learned a lot about Australian history and the system of government. What is the next step in the process?","wordCount":31},{"number":11,"speaker":"ENGLISH","text":"Your application will now go through a final assessment. If approved, you\'ll receive an invitation to attend a citizenship ceremony where you\'ll make the Australian citizenship pledge. This usually takes place within a few months.","wordCount":35},{"number":12,"speaker":"MANDARIN","text":"非常感谢您的详细解释。我全家都非常期待入籍仪式。成为澳大利亚公民对我们来说意义重大。","translation":"Thank you very much for the detailed explanation. My whole family is looking forward to the ceremony. Becoming an Australian citizen means a great deal to us.","wordCount":27}],"totalWords":339},{"id":"immigration-2","domain":"Immigration","title":"Visa Extension — Student Visa","scenario":"This dialogue is a phone conversation between a student and a registered migration agent. The student is calling to ask about extending their student visa, which is due to expire soon. The migration agent explains the requirements, documents needed, and warns about the consequences of letting the visa expire.","englishSpeakerGender":"Female","loteSpeakerGender":"Either","testId":"Practice Batch 2 #001","segments":[{"number":1,"speaker":"ENGLISH","text":"Good morning. This is Sarah from Migration Solutions. How can I assist you today?","wordCount":14},{"number":2,"speaker":"MANDARIN","text":"你好，我是留学生，我的学生签证下个月到期，想咨询续签的事。","translation":"Hello, I am an international student. My student visa expires next month and I want to ask about renewing it.","wordCount":20},{"number":3,"speaker":"ENGLISH","text":"Of course. What course are you enrolled in and have you received a new Confirmation of Enrolment?","wordCount":17},{"number":4,"speaker":"MANDARIN","text":"我在悉尼大学读会计硕士，还有一个学期毕业。学校已经发了新的注册确认书。","translation":"I am studying a Master of Accounting at the University of Sydney with one semester left. The university has issued a new Confirmation of Enrolment.","wordCount":25},{"number":5,"speaker":"ENGLISH","text":"Good. You need to lodge a new student visa application before your current visa expires. You must also show evidence of financial capacity.","wordCount":23},{"number":6,"speaker":"MANDARIN","text":"经济能力证明需要什么？银行存款证明吗？需要多少钱？","translation":"What is needed for proof of financial capacity? A bank statement? How much money is required?","wordCount":16},{"number":7,"speaker":"ENGLISH","text":"You need enough funds for tuition, living expenses, and a return airfare. For living costs, roughly twenty-one thousand dollars a year is required.","wordCount":23},{"number":8,"speaker":"MANDARIN","text":"好的，我父母可以担保。另外，我的海外学生健康保险快到期了，需要续吗？","translation":"OK, my parents can sponsor me. Also, my Overseas Student Health Cover is about to expire. Do I need to renew it?","wordCount":22},{"number":9,"speaker":"ENGLISH","text":"Yes. Your health insurance must cover the full duration of the new visa. You cannot lodge the application without valid cover.","wordCount":21},{"number":10,"speaker":"MANDARIN","text":"如果签证在新申请批下来之前过期了怎么办？我会变成非法滞留吗？","translation":"What if my visa expires before the new application is approved? Will I become an unlawful non-citizen?","wordCount":17},{"number":11,"speaker":"ENGLISH","text":"If you lodge the application before your visa expires, you will automatically receive a bridging visa. This lets you stay in Australia while the application is processed.","wordCount":27},{"number":12,"speaker":"MANDARIN","text":"过桥签证期间我还能工作吗？我目前每两周工作不超过四十八小时。","translation":"Can I still work on the bridging visa? I currently work no more than forty-eight hours per fortnight.","wordCount":18},{"number":13,"speaker":"ENGLISH","text":"Yes, the bridging visa usually has the same work conditions. I recommend you lodge the application as soon as possible to avoid complications.","wordCount":23},{"number":14,"speaker":"MANDARIN","text":"非常感谢。我会尽快准备材料，然后预约来递交申请。","translation":"Thank you very much. I will prepare the documents quickly and make an appointment to lodge the application.","wordCount":18}],"totalWords":284},{"id":"housing-1","domain":"Housing","title":"Rental Application & Inspection","scenario":"This dialogue is a conversation between a prospective tenant and a real estate agent during a rental property inspection. The tenant asks about the lease terms, bond, rent, property condition, and maintenance responsibilities.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"Practice Batch 2 #002","segments":[{"number":1,"speaker":"ENGLISH","text":"Good afternoon. Welcome to Ray White real estate. Are you here for the apartment inspection?","wordCount":15},{"number":2,"speaker":"MANDARIN","text":"是的，我在网上看到了广告，想来实地看看。请问每周租金是多少？","translation":"Yes, I saw the listing online and wanted to have a look in person. How much is the weekly rent?","wordCount":20},{"number":3,"speaker":"ENGLISH","text":"The rent is five hundred and fifty dollars per week, payable fortnightly. The lease is twelve months with an option to renew.","wordCount":22},{"number":4,"speaker":"MANDARIN","text":"押金是多少？新州最近改了规定，最多只能收四周租金作为押金，对吗？","translation":"How much is the bond? New South Wales recently changed the rules so the maximum bond is four weeks of rent, correct?","wordCount":22},{"number":5,"speaker":"ENGLISH","text":"Correct. The bond is four weeks of rent, which is two thousand two hundred dollars. It is lodged with NSW Fair Trading.","wordCount":22},{"number":6,"speaker":"MANDARIN","text":"搬进来之前需要做物业状况报告吗？如果有已存在的损坏，我不想被追究责任。","translation":"Is a property condition report done before moving in? I do not want to be responsible for pre-existing damage.","wordCount":19},{"number":7,"speaker":"ENGLISH","text":"Yes. We provide a condition report with photos. You have seven days to check it and note any issues before returning it.","wordCount":22},{"number":8,"speaker":"MANDARIN","text":"我注意到厨房水龙头在滴水，浴室排气扇也不正常。搬进来前能修好吗？","translation":"I noticed the kitchen tap is dripping and the bathroom exhaust fan is not working. Can these be fixed before I move in?","wordCount":23},{"number":9,"speaker":"ENGLISH","text":"Yes, the landlord is responsible for repairs. We will arrange a plumber and electrician before the lease starts.","wordCount":18},{"number":10,"speaker":"MANDARIN","text":"住进去以后如果热水器或空调坏了，应该联系谁？","translation":"After moving in, if the hot water system or air conditioning breaks down, who should I contact?","wordCount":17},{"number":11,"speaker":"ENGLISH","text":"Contact our office to submit a maintenance request. For urgent issues like burst pipes or no hot water, we have a twenty-four-hour emergency line.","wordCount":24},{"number":12,"speaker":"MANDARIN","text":"这套公寓可以养宠物吗？我有一只小猫。新州法律现在允许租客养宠物了吧？","translation":"Can I keep a pet in this apartment? I have a small cat. New South Wales law now allows tenants to keep pets, right?","wordCount":24},{"number":13,"speaker":"ENGLISH","text":"Yes, pets are allowed under the new legislation. However, you need written consent from the landlord before bringing an animal onto the property.","wordCount":23},{"number":14,"speaker":"MANDARIN","text":"太好了，我很满意这套公寓。请问申请流程是什么？需要提供哪些材料？","translation":"Great, I am very happy with this place. What is the application process and what documents do I need to provide?","wordCount":21}],"totalWords":292},{"id":"housing-2","domain":"Housing","title":"Utilities Dispute — Electricity Bill","scenario":"This dialogue is a phone conversation between a resident and a customer service representative at an electricity provider. The resident is calling to dispute an unusually high electricity bill and to understand the charges. The representative explains possible causes and offers solutions.","englishSpeakerGender":"Female","loteSpeakerGender":"Either","testId":"Practice Batch 2 #003","segments":[{"number":1,"speaker":"ENGLISH","text":"Thank you for calling Energy Australia. My name is Lisa. How may I help you today?","wordCount":16},{"number":2,"speaker":"MANDARIN","text":"你好，我刚收到这个季度的电费账单，金额比上个季度高了快一倍，我觉得不太正常。","translation":"Hello, I just received my quarterly electricity bill and the amount is nearly double last quarter. I think something is wrong.","wordCount":21},{"number":3,"speaker":"ENGLISH","text":"I understand your concern. Could you please give me your account number so I can look into this for you?","wordCount":20},{"number":4,"speaker":"MANDARIN","text":"我的账号是五五三七八二一。这次九百多块，上个季度只有五百左右。我用电习惯没变。","translation":"My account number is five five three seven eight two one. This bill is over nine hundred dollars while last quarter was around five hundred. My usage has not changed.","wordCount":30},{"number":5,"speaker":"ENGLISH","text":"I can see your account. Last quarter was based on an estimated reading, not an actual one. This quarter includes a catch-up adjustment.","wordCount":23},{"number":6,"speaker":"MANDARIN","text":"什么是估算读数？为什么没人来抄电表？我一直在家，没见过任何人来。","translation":"What is an estimated reading? Why did no one come to read the meter? I was home the whole time and never saw anyone.","wordCount":24},{"number":7,"speaker":"ENGLISH","text":"Sometimes meter readers cannot access the property if it is locked or there is a dog in the yard. We can arrange a special reading if you request one.","wordCount":29},{"number":8,"speaker":"MANDARIN","text":"我没有狗，电表在前院很容易进入。不管怎样，这个账单我一次付不起，能分期吗？","translation":"I have no dog and the meter is in the front yard with easy access. Regardless, I cannot pay this all at once. Can I pay in instalments?","wordCount":28},{"number":9,"speaker":"ENGLISH","text":"Yes, we offer payment plans. I can set up a plan where you pay a fixed amount each fortnight until the balance is cleared.","wordCount":24},{"number":10,"speaker":"MANDARIN","text":"请帮我设一个分期计划。另外你们有省电的建议吗？我不想以后再收到这么高的账单。","translation":"Please set up a plan for me. Also, do you have any energy-saving tips? I do not want to receive such a high bill again.","wordCount":25},{"number":11,"speaker":"ENGLISH","text":"You could consider switching to a time-of-use tariff which charges less during off-peak hours. Running appliances like washing machines and dryers at night can reduce your costs significantly.","wordCount":30},{"number":12,"speaker":"MANDARIN","text":"谢谢你的建议，我会试试看。请把分期付款的详细信息发到我的邮箱，我确认一下就可以开始了。","translation":"Thank you for the advice, I will give it a try. Please send the detailed payment plan information to my email and I will confirm it.","wordCount":25}],"totalWords":283},{"id":"insurance-1","domain":"Insurance","title":"Car Accident Insurance Claim","scenario":"This dialogue is a phone conversation between a driver and an insurance company representative. The driver is calling to report a minor car accident and lodge an insurance claim. The representative asks about the details of the incident and explains the claims process.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"Practice Batch 2 #004","segments":[{"number":1,"speaker":"ENGLISH","text":"Good morning. NRMA Insurance claims department. My name is David. How can I help?","wordCount":14},{"number":2,"speaker":"MANDARIN","text":"你好，我昨天下午在停车场发生了一起小车祸，想报保险理赔。","translation":"Hello, I had a minor car accident in a car park yesterday afternoon and I would like to make a claim.","wordCount":21},{"number":3,"speaker":"ENGLISH","text":"I am sorry to hear that. Is anyone injured? Can you tell me what happened?","wordCount":15},{"number":4,"speaker":"MANDARIN","text":"没有人受伤。我在Westfield停车场倒车时，另一辆车从后面撞到了我车的右侧。","translation":"No one was injured. I was reversing in the Westfield car park when another car hit the right side of my vehicle from behind.","wordCount":24},{"number":5,"speaker":"ENGLISH","text":"Did you exchange details with the other driver? I need their name, phone number, registration plate, and insurance details.","wordCount":19},{"number":6,"speaker":"MANDARIN","text":"是的，对方叫约翰\xb7史密斯，车牌号DFG-234。但他说没有买保险。","translation":"Yes, the other driver is John Smith with registration plate DFG-234. But he said he does not have insurance.","wordCount":19},{"number":7,"speaker":"ENGLISH","text":"That is fine. We can still process your claim. Did you take photos of the damage and the accident scene?","wordCount":20},{"number":8,"speaker":"MANDARIN","text":"拍了很多照片。我车门上有大凹痕，右后视镜碎了。对方前保险杠也有刮痕。","translation":"I took many photos. There is a large dent on my door and the right mirror is smashed. The other car has scratches on the front bumper.","wordCount":27},{"number":9,"speaker":"ENGLISH","text":"Good, photos are very helpful. Did you report the accident to the police?","wordCount":13},{"number":10,"speaker":"MANDARIN","text":"没有报警，因为没人受伤，损失也不太严重。需要报警吗？","translation":"I did not call the police because no one was hurt and the damage was not serious. Do I need to report it?","wordCount":23},{"number":11,"speaker":"ENGLISH","text":"For minor accidents with no injuries, a police report is not required. But I suggest you report it online for your records. Let me explain the claims process.","wordCount":28},{"number":12,"speaker":"MANDARIN","text":"好的，请说。我需要先垫付修理费吗？","translation":"OK, please go ahead. Do I need to pay for repairs upfront?","wordCount":12},{"number":13,"speaker":"ENGLISH","text":"You need to pay the excess, which is your contribution towards the claim. Your policy has a basic excess of eight hundred dollars. We will send an assessor to inspect your car.","wordCount":32},{"number":14,"speaker":"MANDARIN","text":"八百块免赔额，明白了。如果查明是对方全责，免赔额能退给我吗？","translation":"Eight hundred dollars excess, I understand. If the other driver is found fully at fault, can the excess be refunded?","wordCount":20}],"totalWords":287},{"id":"business-1","domain":"Business","title":"Small Business — Export Inquiry","scenario":"This dialogue is a conversation between a small business owner and an Austrade trade officer. The business owner is seeking advice about exporting Australian skincare products to China. The trade officer explains export regulations, tariffs, labelling requirements, and government support programs.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"Practice Batch 2 #005","segments":[{"number":1,"speaker":"ENGLISH","text":"Good morning. Welcome to Austrade. I am James, a trade officer. I understand you are interested in exporting to China.","wordCount":20},{"number":2,"speaker":"MANDARIN","text":"是的，我经营一家小型护肤品公司，产品在澳洲卖得很好，现在想拓展中国市场。","translation":"Yes, I run a small skincare company. Our products sell well in Australia and we want to expand into the Chinese market.","wordCount":22},{"number":3,"speaker":"ENGLISH","text":"That is a great opportunity. Australian skincare products are highly regarded in China. However, exporting cosmetics requires meeting specific regulations in both countries.","wordCount":23},{"number":4,"speaker":"MANDARIN","text":"我对出口法规不太了解。产品需要在中国注册吗？大概要多长时间？","translation":"I do not know much about export regulations. Do my products need to be registered in China? How long does it take?","wordCount":22},{"number":5,"speaker":"ENGLISH","text":"Yes, cosmetics must be registered with the National Medical Products Administration in China. For ordinary cosmetics, the process takes three to six months.","wordCount":23},{"number":6,"speaker":"MANDARIN","text":"关税方面呢？中国对澳洲护肤品的进口关税是多少？中澳自贸协定有帮助吗？","translation":"What about tariffs? What is the import duty on Australian skincare products in China? Does the China-Australia Free Trade Agreement help?","wordCount":21},{"number":7,"speaker":"ENGLISH","text":"Under the Free Trade Agreement, tariffs on many Australian goods have been reduced or eliminated. For cosmetics, the tariff may be as low as five per cent.","wordCount":27},{"number":8,"speaker":"MANDARIN","text":"那很好。产品标签有特殊要求吗？我知道中国对进口产品标签要求很严格。","translation":"That is good. Are there special labelling requirements? I know China has strict labelling rules for imported products.","wordCount":18},{"number":9,"speaker":"ENGLISH","text":"All products need Chinese language labels showing ingredients, manufacturer details, expiry date, and the name of the Chinese importer. Labels must meet national standards.","wordCount":24},{"number":10,"speaker":"MANDARIN","text":"听起来很复杂。政府有支持计划帮助小企业出口吗？补贴或培训都行。","translation":"That sounds complicated. Does the government have programs to help small businesses export? Grants or training would be helpful.","wordCount":19},{"number":11,"speaker":"ENGLISH","text":"Yes. The Export Market Development Grant reimburses up to fifty per cent of eligible export expenses. We also offer free workshops and can arrange trade missions to China.","wordCount":28},{"number":12,"speaker":"MANDARIN","text":"太好了，这正是我需要的。能预约一个详细的咨询吗？我想尽快开始准备。","translation":"That is exactly what I need. Can I book a detailed consultation? I want to start preparing as soon as possible.","wordCount":21}],"totalWords":268}]')}}]);